@import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Inter:wght@400;600;700&display=swap');
@import "tailwindcss";

@theme {
  --font-sans: "Inter", ui-sans-serif, system-ui, sans-serif;
  --font-display: "Bebas Neue", sans-serif;
  --color-high-vis-orange: #f5d000;
  --color-electric-cyan: #22d3ee;
  --color-deep-slate: #0f1933;
  --color-charcoal: #d9dce2;
}

@layer utilities {
  .brutal-border { border: var(--b); }
  .brutal-shadow { box-shadow: var(--sh); }
  .brutal-shadow-lg { box-shadow: var(--shl); }

  .glow-cyan { box-shadow: var(--sh); }
  .glow-orange { box-shadow: var(--shl); }

  .glass-nav {
    background: var(--n);
    border-bottom: 4px solid var(--y);
  }
  .glow-orange {
    box-shadow: 0 0 20px rgba(245, 208, 0, 0.35);
  }

  .brutal-btn:hover {
    transform: translate(-2px, -2px);
    box-shadow: var(--shl);
  }

  .brutal-btn:active {
    transform: translate(2px, 2px);
