145	  // ── Tool: Quote Quick Builder ────────────────────────────────────────────────
146	  const [qtLabour, setQtLabour] = useState(6);
147	  const [qtRate, setQtRate] = useState(35);
148	  const [qtMaterials, setQtMaterials] = useState(120);
149	  const [qtMarkup, setQtMarkup] = useState(20);
150	  const qtMaterialsTotal = qtMaterials * (1 + qtMarkup / 100);
151	  const qtLabourTotal = qtLabour * qtRate;
152	  const qtTotal = qtLabourTotal + qtMaterialsTotal;
