154	  // ── Tool: Day Rate Calculator ────────────────────────────────────────────────
155	  const [drAnnualTarget, setDrAnnualTarget] = useState(40000);
156	  const [drDaysWorked, setDrDaysWorked] = useState(220);
157	  const [drOverheads, setDrOverheads] = useState(5000);
