192	    return Math.round((base[teScope] || 6) * (tradeMulti[teTrade] || 1) * (accessMulti[teAccess] || 1));
193	  };
194	  const teHours = getTeHours();
195	
196	  // ── Tool: Fuel Cost Calculator ───────────────────────────────────────────────
197	  const [fcMiles, setFcMiles] = useState(20);
198	  const [fcMpg, setFcMpg] = useState(35);
199	  const [fcPrice, setFcPrice] = useState(148);
200	  const [fcTrips, setFcTrips] = useState(1);

