@import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Inter:wght@400;600;700&display=swap');
@import "tailwindcss";

@theme {
  --font-sans: "Inter", ui-sans-serif, system-ui, sans-serif;
  --font-display: "Bebas Neue", sans-serif;
  --color-high-vis-orange: #f5d000;
  --color-deep-slate: #0f1933;
  --color-charcoal: #d9dce2;
}

@layer utilities {
  .brutal-border { border: 3px solid #0f1933; }
  .brutal-shadow { box-shadow: 4px 4px 0 #0f1933; }
  .brutal-shadow-lg { box-shadow: 6px 6px 0 #0f1933; }

  .glow-orange {
    box-shadow: 0 0 20px rgba(245, 208, 0, 0.35);
  }

  .glass-nav {
    background: rgba(15, 25, 51, 0.85);
    border-bottom: 4px solid #f5d000;
  }

  .brutal-btn {
    background: #f5d000;
    border: 3px solid #0f1933;
    box-shadow: 4px 4px 0 #0f1933;
    color: #0f1933;
    font-family: "Bebas Neue", sans-serif;
    font-weight: 900;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    padding: 0.625rem 1.5rem;
    transition: all 0.1s ease;
  }

  .brutal-btn:hover {
    transform: translate(-2px, -2px);
    box-shadow: 6px 6px 0 #0f1933;
  }

  .brutal-btn:active {
    transform: translate(2px, 2px);
    box-shadow: 2px 2px 0 #0f1933;
  }

  .classic-theme {
    background: #e5e7eb;
    color: #0f1933;
  }

  .classic-panel {
    background: #f8f8f8;
    border: 3px solid #0f1933;
    box-shadow: 6px 6px 0 #0f1933;
  }

  .classic-btn {
    background: #f5d000;
    border: 3px solid #0f1933;
    box-shadow: 4px 4px 0 #0f1933;
    transition: all 0.1s ease;
  }

  .classic-btn:hover {
    filter: brightness(0.95);
  }

  .classic-btn-secondary {
    background: #0f1933;
    border: 3px solid #0f1933;
    box-shadow: 4px 4px 0 #0f1933;
    color: #f8f8f8;
    transition: all 0.1s ease;
  }

  .classic-btn-secondary:hover {
    background: #172447;
  }
}

@keyframes scan {
  0% { top: 0; }
  100% { top: 100%; }
}

@keyframes pulse-glow {
  0%, 100% { box-shadow: 0 0 20px rgba(245,208,0,0.5); }
  50% { box-shadow: 0 0 40px rgba(245,208,0,0.9); }
}

.animate-scan { animation: scan 2s linear infinite; }
.founding-pulse { animation: pulse-glow 2s ease-in-out infinite; }

